  // Why Nomiqa Section
  whyNomiqaMainTitle: { EN: "This Is Why You Need Nomiqa", ES: "Por Esto Necesitas Nomiqa", FR: "C'est Pourquoi Vous Avez Besoin de Nomiqa", DE: "Deshalb Brauchen Sie Nomiqa", RU: "Вот Почему Вам Нужна Nomiqa", ZH: "这就是您需要Nomiqa的原因", JA: "これがNomiqaが必要な理由", PT: "É Por Isso Que Você Precisa da Nomiqa", AR: "لهذا السبب تحتاج إلى Nomiqa", HI: "इसीलिए आपको Nomiqa की आवश्यकता है" },
  whyNomiqaMainSubtitle: { EN: "Because your freedom shouldn't come with surveillance.", ES: "Porque tu libertad no debería venir con vigilancia.", FR: "Parce que votre liberté ne devrait pas s'accompagner de surveillance.", DE: "Denn Ihre Freiheit sollte nicht mit Überwachung einhergehen.", RU: "Потому что ваша свобода не должна сопровождаться наблюдением.", ZH: "因为您的自由不应该伴随监视。", JA: "あなたの自由は監視を伴うべきではないからです。", PT: "Porque sua liberdade não deve vir com vigilância.", AR: "لأن حريتك لا يجب أن تأتي مع المراقبة.", HI: "क्योंकि आपकी स्वतंत्रता निगरानी के साथ नहीं आनी चाहिए।" },
  whyNomiqaPrivacyTitle: { EN: "True Privacy. Zero Compromise.", ES: "Privacidad Real. Cero Compromisos.", FR: "Vraie Confidentialité. Zéro Compromis.", DE: "Wahre Privatsphäre. Null Kompromisse.", RU: "Настоящая Конфиденциальность. Без Компромиссов.", ZH: "真正的隐私。零妥协。", JA: "本当のプライバシー。妥協なし。", PT: "Privacidade Verdadeira. Zero Compromisso.", AR: "خصوصية حقيقية. صفر تنازلات.", HI: "सच्ची गोपनीयता। शून्य समझौता।" },
  whyNomiqaPrivacyDesc: { EN: "Your data is YOURS. No ID checks, no surveillance, no digital footprints.", ES: "Tus datos son TUYOS. Sin verificación de ID, sin vigilancia, sin huellas digitales.", FR: "Vos données sont à VOUS. Pas de vérification d'identité, pas de surveillance, pas d'empreintes numériques.", DE: "Ihre Daten gehören IHNEN. Keine Ausweiskontrollen, keine Überwachung, keine digitalen Spuren.", RU: "Ваши данные — ВАШИ. Без проверки документов, без наблюдения, без цифровых следов.", ZH: "您的数据是您的。无需身份检查、无监视、无数字足迹。", JA: "あなたのデータはあなたのものです。ID確認なし、監視なし、デジタル足跡なし。", PT: "Seus dados são SEUS. Sem verificação de ID, sem vigilância, sem pegadas digitais.", AR: "بياناتك ملكك. بدون فحوصات الهوية، بدون مراقبة، بدون بصمات رقمية.", HI: "आपका डेटा आपका है। कोई ID जाँच नहीं, कोई निगरानी नहीं, कोई डिजिटल पदचिह्न नहीं।" },
  whyNomiqaAccessTitle: { EN: "Instant Access. Real Freedom.", ES: "Acceso Instantáneo. Libertad Real.", FR: "Accès Instantané. Vraie Liberté.", DE: "Sofortiger Zugriff. Echte Freiheit.", RU: "Мгновенный Доступ. Настоящая Свобода.", ZH: "即时访问。真正的自由。", JA: "即座のアクセス。本当の自由。", PT: "Acesso Instantâneo. Liberdade Real.", AR: "وصول فوري. حرية حقيقية.", HI: "तत्काल पहुंच। असली स्वतंत्रता।" },
  whyNomiqaAccessDesc: { EN: "Pay with crypto. Activate in seconds. No banks watching. No delays.", ES: "Paga con crypto. Activa en segundos. Sin bancos observando. Sin demoras.", FR: "Payez en crypto. Activez en secondes. Pas de banques qui regardent. Pas de retards.", DE: "Mit Krypto bezahlen. In Sekunden aktivieren. Keine Banken, die zusehen. Keine Verzögerungen.", RU: "Платите криптовалютой. Активируйте за секунды. Без банковского контроля. Без задержек.", ZH: "用加密货币支付。几秒钟内激活。无需银行监视。无延迟。", JA: "暗号通貨で支払う。数秒でアクティベート。銀行の監視なし。遅延なし。", PT: "Pague com cripto. Ative em segundos. Sem bancos observando. Sem atrasos.", AR: "ادفع بالعملات المشفرة. فعّل في ثوانٍ. بدون بنوك تراقب. بدون تأخير.", HI: "क्रिप्टो से भुगतान करें। सेकंड में सक्रिय करें। कोई बैंक देख रहा नहीं। कोई देरी नहीं।" },
  whyNomiqaBorderlessTitle: { EN: "Borderless Connection. Limitless Possibilities.", ES: "Conexión Sin Fronteras. Posibilidades Ilimitadas.", FR: "Connexion Sans Frontières. Possibilités Illimitées.", DE: "Grenzenlose Verbindung. Unbegrenzte Möglichkeiten.", RU: "Связь Без Границ. Безграничные Возможности.", ZH: "无国界连接。无限可能。", JA: "ボーダレス接続。無限の可能性。", PT: "Conexão Sem Fronteiras. Possibilidades Ilimitadas.", AR: "اتصال بلا حدود. إمكانيات لا حدود لها.", HI: "सीमारहित कनेक्शन। असीमित संभावनाएं।" },
  whyNomiqaBorderlessDesc: { EN: "190+ countries. One eSIM. The world is yours to explore freely.", ES: "Más de 190 países. Una eSIM. El mundo es tuyo para explorar libremente.", FR: "Plus de 190 pays. Une eSIM. Le monde est à vous pour l'explorer librement.", DE: "190+ Länder. Eine eSIM. Die Welt gehört Ihnen zur freien Erkundung.", RU: "190+ стран. Одна eSIM. Мир — ваш для свободного исследования.", ZH: "190多个国家。一张eSIM。世界由您自由探索。", JA: "190以上の国。1つのeSIM。世界はあなたが自由に探索するものです。", PT: "Mais de 190 países. Um eSIM. O mundo é seu para explorar livremente.", AR: "أكثر من 190 دولة. eSIM واحد. العالم ملكك لاستكشافه بحرية.", HI: "190+ देश। एक eSIM। दुनिया आपकी है स्वतंत्र रूप से अन्वेषण करने के लिए।" },

